import { Card, Checkbox, FormControlLabel, FormGroup, Grid2, IconButton, Stack, Typography } from '@mui/material';
import FilterListIcon from '@mui/icons-material/FilterList';
import FilterListOffIcon from '@mui/icons-material/FilterListOff';
import { GridColDef } from '@mui/x-data-grid';

import { useCallback, useMemo, useState } from 'react';
import { useDispatch } from 'react-redux';

import AddButton from '../components/shared/AddButton';
import { AppCard } from '../components/shared/AppCard';
import { AppDataGrid } from '../components/shared/AppDataGrid';
import { AppGridContainer } from '../components/shared/AppGridContainer';
import { useAppFurniture } from '../hooks/useAppFurniture';
import { useCategories } from '../hooks/useCategories';
import { AppDispatch } from '../store';
import { createFurniture, deleteFurniture, updateFurniture } from '../store/furnitureReducer';

import { Furniture } from '@umzug-meister/um-core';

export default function FurnitureRoute() {
  const furniture = useAppFurniture();
  const categories = useCategories();
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<(string | number)[]>([]);
  const [showWithoutCategory, setShowWithoutCategory] = useState(false);
  const [filterBarVisible, setFilterBarVisible] = useState(false);

  const dispatch = useDispatch<AppDispatch>();

  const filteredFurniture = useMemo(() => {
    if (selectedCategoryIds.length === 0 && !showWithoutCategory) {
      return furniture;
    }
    return furniture.filter((item) => {
      const hasNoCategory = !item.categoryRefs || item.categoryRefs.length === 0;
      if (showWithoutCategory && hasNoCategory) return true;
      return item.categoryRefs?.some((cat) => selectedCategoryIds.includes(cat.id));
    });
  }, [furniture, selectedCategoryIds, showWithoutCategory]);

  const handleCategoryFilterChange = useCallback((checked: boolean, catId: string | number) => {
    setSelectedCategoryIds((prev) => {
      if (checked) {
        return [...prev, catId];
      }
      return prev.filter((id) => id !== catId);
    });
  }, []);

  const onUpdate = useCallback(
    (f: Furniture) => {
      return dispatch(updateFurniture(f));
    },
    [dispatch],
  );

  const onAdd = useCallback(() => {
    dispatch(createFurniture());
  }, [dispatch]);

  const onDelete = useCallback(
    (id: number) => {
      dispatch(deleteFurniture(id));
    },
    [dispatch],
  );

  const renderCategoryRefs = useCallback(
    (row: Furniture) => {
      const next = { ...row };

      const isChecked = (categoryId: string | number) => {
        return row.categoryRefs?.some((c) => Number(c.id) === Number(categoryId)) || false;
      };

      const onChange = (checked: boolean, catId: string | number) => {
        if (checked) {
          const newCategory = categories.find((c) => Number(c.id) === Number(catId));

          if (newCategory) {
            next.categoryRefs = [...(next.categoryRefs || []), newCategory];
          }
        } else {
          const newcats = next.categoryRefs.filter((c) => Number(c.id) !== Number(catId));
          if (newcats.length === 0) {
            alert('Mindestens eine Kategorie muss ausgewählt sein!');
            return;
          }
          next.categoryRefs = newcats;
        }
        dispatch(updateFurniture(next));
      };

      return (
        <FormGroup row>
          {categories.map((cat) => (
            <FormControlLabel
              key={cat.id}
              label={cat.name}
              control={
                <Checkbox
                  checked={isChecked(cat.id)}
                  onChange={(ev) => {
                    onChange(ev.target.checked, cat.id);
                  }}
                />
              }
            />
          ))}
        </FormGroup>
      );
    },
    [categories, dispatch],
  );

  const columns: GridColDef[] = [
    {
      field: 'id',
      headerName: 'ID',
    },
    {
      field: 'name',
      headerName: 'Name',
      editable: true,
      width: 200,
    },
    {
      field: 'categoryRefs',
      headerName: 'Kategorien',
      flex: 1,
      renderCell: ({ row }) => renderCategoryRefs(row),
    },
    {
      field: 'volume',
      headerName: 'Volume',
      type: 'number',
      width: 70,
      editable: true,
    },
    {
      field: 'step',
      headerName: 'Schritt',
      type: 'number',
      width: 70,

      editable: true,
    },
    {
      field: 'sortOrder',
      type: 'number',
      editable: true,
      width: 80,

      headerName: 'Sortierung',
    },
  ];

  return (
    <AppGridContainer>
      <Grid2 size={12}>
        <AppCard title="Möbel">
          <Stack direction="row" spacing={1} alignItems="center">
            <AddButton onClick={onAdd} />
            <IconButton
              color={filterBarVisible ? 'primary' : 'default'}
              onClick={() => {
                setFilterBarVisible((prev) => !prev);
                if (filterBarVisible) {
                  setSelectedCategoryIds([]);
                  setShowWithoutCategory(false);
                }
              }}
            >
              {filterBarVisible ? <FilterListOffIcon /> : <FilterListIcon />}
            </IconButton>
            {filterBarVisible && (
              <Card variant="outlined" sx={{ flex: 1 }}>
                <FormGroup row sx={{ px: 1 }}>
                  <Typography variant="subtitle2" color="primary" fontWeight="bold" sx={{ mr: 1, alignSelf: 'center' }}>
                    Kategorie:
                  </Typography>
                  <FormControlLabel
                    label="Ohne Kategorie"
                    control={
                      <Checkbox
                        checked={showWithoutCategory}
                        onChange={(ev) => setShowWithoutCategory(ev.target.checked)}
                      />
                    }
                  />
                  {categories.map((cat) => (
                    <FormControlLabel
                      key={cat.id}
                      label={cat.name}
                      control={
                        <Checkbox
                          checked={selectedCategoryIds.includes(cat.id)}
                          onChange={(ev) => handleCategoryFilterChange(ev.target.checked, cat.id)}
                        />
                      }
                    />
                  ))}
                </FormGroup>
              </Card>
            )}
          </Stack>
          <AppDataGrid
            loading={false}
            columns={columns}
            data={filteredFurniture}
            paginationMode="client"
            disablePagination
            allowDeletion
            onDelete={onDelete}
            onUpdate={onUpdate}
          />
        </AppCard>
      </Grid2>
    </AppGridContainer>
  );
}
